<template>
  <b-field :label="liabilityAdded" :addons="false" class="info">
    <b-tooltip label="Please list all liabilities that you have incurred." position="is-left" size="is-medium" type="is-dark" animated multilined v-once>
      <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
    </b-tooltip>
    <b-field>
      <b-input v-model="liabilityType" type="text" :icon="typeIcon" style="flex:3;" placeholder="I owe"></b-input>
      <b-input v-model="liabilityValue" :icon="valueIcon" style="flex:2;" placeholder="CAD"></b-input>
      <span class="control">
        <button class="button is-outlined is-primary" v-if="adding" @click="addField" :disabled="empty || full">
          <i class="fas fa-plus"></i>&ensp;Add</button>
        <button class="button is-outlined is-danger" v-else @click="removeField">
          <i class="fas fa-minus"></i>&ensp;Remove</button>
      </span>
    </b-field>
  </b-field>
</template>

<script>
export default {
  methods: {
    addField() {
      if (this.liabilityType.length > 2 && this.liabilityValue.length > 2) {
        if (this.$store.state.AssetsLiabilitiesForm.liabilities.length < 6) {
          this.$store.dispatch("addLiability", {
            type: this.liabilityType,
            value: this.liabilityValue
          });
          this.$store.dispatch("clearField", "liabilities");
        }
      }
    },
    removeField() {
      if (this.$store.state.AssetsLiabilitiesForm.liabilities.length > 1) {
        this.$store.dispatch("removeLiability", {
          type: this.liabilityType,
          value: this.liabilityValue
        });
      }
    }
  },
  computed: {
    empty() {
      return this.liabilityType.length < 2 && this.liabilityValue.length < 2;
    },
    full() {
      return this.$store.state.AssetsLiabilitiesForm.liabilities.length === 5;
    },
    noLiability() {
      return this.$store.state.AssetsLiabilitiesForm.liabilities.length === 0;
    },
    liabilityType: {
      get() {
        return this.$store.state.AssetsLiabilitiesForm.liabilities[this.ind]
          .type;
      },
      set(val) {
        this.$store.state.AssetsLiabilitiesForm.liabilities[
          this.ind
        ].type = val;
      }
    },
    liabilityValue: {
      get() {
        return this.$store.state.AssetsLiabilitiesForm.liabilities[this.ind]
          .value;
      },
      set(val) {
        this.$store.state.AssetsLiabilitiesForm.liabilities[
          this.ind
        ].value = val;
      }
    },
    adding() {
      return this.ind > 0 ? false : true;
    },
    liabilityAdded() {
      return this.adding ? "Liability" : "Liability added";
    },
    typeIcon() {
      if (this.adding) {
        return "credit-card";
      } else {
        return "check-square";
      }
    },
    valueIcon() {
      if (this.adding) {
        return "dollar-sign";
      } else {
        return "check-square";
      }
    }
  },
  props: {
    ind: Number
  }
};
</script>
